import type { DocumentPostingStatus, DocumentPostingStatusResult } from '../services/kt/models';
import { pollDocumentPostingStatus } from './pollDocumentPostingStatus';

export type PostingStatusGetter = (id: string) => Promise<DocumentPostingStatusResult>;

/**
 * SSOT refresh toolbar sau Phê duyệt / Lưu đổi mức xử lý — PT · PC · BC · BN · UNC (cash-voucher stack).
 */
export async function refreshPostingStatusAfterLevelChange(params: {
  previousLevel: string;
  newLevel: string;
  voucherId: string;
  getPostingStatus: PostingStatusGetter;
  onPostingStatus: (status: DocumentPostingStatus) => void;
  reloadDocument: (voucherId: string) => Promise<void>;
  onPostSuccess?: () => void;
  onError: (message: string) => void;
}): Promise<void> {
  const {
    previousLevel,
    newLevel,
    voucherId,
    getPostingStatus,
    onPostingStatus,
    reloadDocument,
    onPostSuccess,
    onError,
  } = params;

  const wasAutoPost = previousLevel === '9';
  const isAutoPost = newLevel === '9';

  if (isAutoPost) {
    const ps = await getPostingStatus(voucherId);
    onPostingStatus(ps.postingStatus);
    if (ps.postingStatus === 'Queued' || ps.postingStatus === 'Processing') {
      const final = await pollDocumentPostingStatus(() => getPostingStatus(voucherId));
      onPostingStatus(final.postingStatus);
      if (final.postingStatus === 'Failed' && final.lastError) {
        onError(final.lastError);
        return;
      }
      if (final.postingStatus === 'Posted') {
        await reloadDocument(voucherId);
        onPostingStatus('Posted');
        onPostSuccess?.();
      }
    } else if (ps.postingStatus === 'Posted') {
      await reloadDocument(voucherId);
      onPostingStatus('Posted');
    }
    return;
  }

  if (wasAutoPost && !isAutoPost) {
    await reloadDocument(voucherId);
    const ps = await getPostingStatus(voucherId);
    onPostingStatus(ps.postingStatus);
    if (ps.postingStatus === 'Queued' || ps.postingStatus === 'Processing') {
      const final = await pollDocumentPostingStatus(() => getPostingStatus(voucherId));
      onPostingStatus(final.postingStatus);
      if (final.postingStatus === 'Failed' && final.lastError) {
        onError(final.lastError);
      }
    }
  }
}

/** Load + poll khi mở form — job Queued/Processing hoặc Posted cần reload DTO. */
export async function loadPostingStatusForOpenForm(params: {
  voucherId: string;
  getPostingStatus: PostingStatusGetter;
  onPostingStatus: (status: DocumentPostingStatus) => void;
  reloadIfPosted: (voucherId: string) => Promise<boolean>;
  onError: (message: string) => void;
}): Promise<void> {
  const { voucherId, getPostingStatus, onPostingStatus, reloadIfPosted, onError } = params;
  const ps = await getPostingStatus(voucherId);
  onPostingStatus(ps.postingStatus);

  if (ps.postingStatus !== 'Queued' && ps.postingStatus !== 'Processing') {
    if (ps.postingStatus === 'Posted') {
      await reloadIfPosted(voucherId);
    }
    return;
  }

  const final = await pollDocumentPostingStatus(() => getPostingStatus(voucherId));
  onPostingStatus(final.postingStatus);
  if (final.postingStatus === 'Posted') {
    await reloadIfPosted(voucherId);
  } else if (final.postingStatus === 'Failed' && final.lastError) {
    onError(final.lastError);
  }
}
